/**
 * Media Library Tab
 *
 * Unified browser for all media generated by tool services.
 * Shows tool cards with file counts, expandable file grids with thumbnails,
 * lightbox preview, download/open actions, and batch thumbnail generation.
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
  Image,
  Film,
  Music,
  FileText,
  Archive,
  File,
  FileCode,
  Table,
  Download,
  ExternalLink,
  X,
  ChevronLeft,
  ChevronRight,
  Loader2,
  FolderOpen,
  HardDrive,
  ArrowUpDown,
  Grid,
  List,
  Trash2,
  Eye,
  ChevronDown,
  Play,
} from 'lucide-react';
import { mediaLibraryService } from '@/services/mediaLibrary';
import { useAuthStore } from '@/stores/auth';
import type { ToolMediaSummary, MediaFile, MediaStats } from '@/types';

// =============================================================================
// Constants
// =============================================================================

const MEDIA_TYPE_ICONS: Record<string, { icon: React.ElementType; color: string }> = {
  image: { icon: Image, color: 'text-neon-cyan' },
  video: { icon: Film, color: 'text-purple-400' },
  audio: { icon: Music, color: 'text-neon-green' },
  document: { icon: FileText, color: 'text-yellow-400' },
  archive: { icon: Archive, color: 'text-orange-400' },
  code: { icon: FileCode, color: 'text-blue-400' },
  spreadsheet: { icon: Table, color: 'text-green-400' },
  other: { icon: File, color: 'text-gray-400' },
};

const TOOL_ICON_MAP: Record<string, string> = {
  music: '🎵',
  image: '🖼️',
  video: '🎬',
  audio: '🔊',
  document: '📄',
  archive: '📦',
};

// =============================================================================
// Helpers
// =============================================================================

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
}

function formatTimeAgo(dateStr: string): string {
  const now = new Date();
  const date = new Date(dateStr);
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  if (diffMins < 1) return 'just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  const diffHrs = Math.floor(diffMins / 60);
  if (diffHrs < 24) return `${diffHrs}h ago`;
  const diffDays = Math.floor(diffHrs / 24);
  if (diffDays < 30) return `${diffDays}d ago`;
  return date.toLocaleDateString();
}

function getMediaTypeIcon(mediaType: string) {
  return MEDIA_TYPE_ICONS[mediaType] || MEDIA_TYPE_ICONS.other;
}

// =============================================================================
// Hook: Authenticated blob URL fetcher
// =============================================================================

/**
 * Fetches a media endpoint with JWT auth and returns a revocable blob URL.
 * Cleans up on unmount / dependency change.
 */
function useAuthBlobUrl(
  fetcher: (() => Promise<string>) | null
): { url: string | null; loading: boolean; error: boolean } {
  const [url, setUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(!!fetcher);
  const [error, setError] = useState(false);

  useEffect(() => {
    if (!fetcher) {
      setUrl(null);
      setLoading(false);
      return;
    }
    let cancelled = false;
    let blobUrl: string | null = null;
    setLoading(true);
    setError(false);

    fetcher()
      .then((u) => {
        if (!cancelled) {
          blobUrl = u;
          setUrl(u);
          setLoading(false);
        } else {
          URL.revokeObjectURL(u);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setError(true);
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
      if (blobUrl) URL.revokeObjectURL(blobUrl);
    };
  }, [fetcher]);

  return { url, loading, error };
}

// =============================================================================
// Thumbnail Image Component with lazy load + fade-in
// =============================================================================

interface ThumbnailImageProps {
  toolSlug: string;
  file: MediaFile;
  className?: string;
}

const ThumbnailImage: React.FC<ThumbnailImageProps> = ({ toolSlug, file, className = '' }) => {
  const { icon: Icon, color } = getMediaTypeIcon(file.media_type);

  const fetcher = useCallback(
    () => file.thumbnail_url
      ? mediaLibraryService.fetchThumbnailBlobUrl(toolSlug, file.filename)
      : Promise.reject('no thumbnail'),
    [toolSlug, file.filename, file.thumbnail_url]
  );

  const { url: thumbUrl, loading, error: errored } = useAuthBlobUrl(
    file.thumbnail_url ? fetcher : null
  );

  if (!file.thumbnail_url || errored) {
    return (
      <div className={`flex items-center justify-center bg-navy-900/60 ${className}`}>
        <Icon className={`h-10 w-10 ${color} opacity-60`} />
      </div>
    );
  }

  return (
    <div className={`relative bg-navy-900/60 ${className}`}>
      {(loading || !thumbUrl) && (
        <div className="absolute inset-0 flex items-center justify-center">
          <Icon className={`h-10 w-10 ${color} opacity-40`} />
        </div>
      )}
      {thumbUrl && (
        <img
          src={thumbUrl}
          alt={file.filename}
          className={`w-full h-full object-cover transition-opacity duration-300 ${
            loading ? 'opacity-0' : 'opacity-100'
          }`}
        />
      )}
    </div>
  );
};

// =============================================================================
// Lightbox Component
// =============================================================================

interface LightboxProps {
  file: MediaFile;
  toolSlug: string;
  files: MediaFile[];
  onClose: () => void;
  onNavigate: (file: MediaFile) => void;
}

const Lightbox: React.FC<LightboxProps> = ({ file, toolSlug, files, onClose, onNavigate }) => {
  const currentIndex = files.findIndex((f) => f.filename === file.filename);

  const fileFetcher = useCallback(
    () => mediaLibraryService.fetchFileBlobUrl(toolSlug, file.filename),
    [toolSlug, file.filename]
  );
  const { url: fileUrl, loading: fileLoading } = useAuthBlobUrl(fileFetcher);

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft' && currentIndex > 0) onNavigate(files[currentIndex - 1]);
      if (e.key === 'ArrowRight' && currentIndex < files.length - 1) onNavigate(files[currentIndex + 1]);
    },
    [currentIndex, files, onClose, onNavigate]
  );

  useEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    document.body.style.overflow = 'hidden';
    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.body.style.overflow = '';
    };
  }, [handleKeyDown]);

  const handleDownload = useCallback(async (e: React.MouseEvent) => {
    e.preventDefault();
    try {
      await mediaLibraryService.downloadFile(toolSlug, file.filename);
    } catch {
      // Silently fail — user will see nothing downloaded
    }
  }, [toolSlug, file.filename]);

  const handleOpenNewTab = useCallback(async (e: React.MouseEvent) => {
    e.preventDefault();
    try {
      const blobUrl = await mediaLibraryService.fetchFileBlobUrl(toolSlug, file.filename);
      window.open(blobUrl, '_blank');
    } catch {
      // Silently fail
    }
  }, [toolSlug, file.filename]);

  return (
    <div
      className="fixed inset-0 z-50 bg-black/90 backdrop-blur-sm flex flex-col"
      onClick={onClose}
    >
      {/* Top bar */}
      <div
        className="flex items-center justify-between px-6 py-4 bg-navy-950/90 border-b border-gray-700/50"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center gap-3 text-gray-300 text-sm">
          <span className="font-medium text-white">{file.filename}</span>
          <span className="text-gray-500">·</span>
          <span>{formatBytes(file.size_bytes)}</span>
          <span className="text-gray-500">·</span>
          <span>{formatTimeAgo(file.modified_at)}</span>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={handleOpenNewTab}
            className="p-2 text-gray-300 hover:text-white transition-colors rounded-lg hover:bg-white/10 border border-transparent hover:border-gray-600"
            title="Open in new tab"
          >
            <ExternalLink className="h-5 w-5" />
          </button>
          <button
            onClick={handleDownload}
            className="p-2 text-gray-300 hover:text-neon-cyan transition-colors rounded-lg hover:bg-neon-cyan/10 border border-transparent hover:border-neon-cyan/30"
            title="Download"
          >
            <Download className="h-5 w-5" />
          </button>
          <button
            onClick={onClose}
            className="ml-2 p-2 text-white bg-white/10 hover:bg-red-500/80 transition-colors rounded-lg border border-gray-600 hover:border-red-400"
            title="Close (Esc)"
          >
            <X className="h-5 w-5" />
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 flex items-center justify-center px-16 py-8 relative">
        {/* Nav arrows */}
        {currentIndex > 0 && (
          <button
            onClick={(e) => { e.stopPropagation(); onNavigate(files[currentIndex - 1]); }}
            className="absolute left-4 p-3 text-white bg-black/50 hover:bg-white/20 rounded-full transition-all border border-white/20 hover:border-white/40 shadow-lg z-10"
          >
            <ChevronLeft className="h-8 w-8" />
          </button>
        )}
        {currentIndex < files.length - 1 && (
          <button
            onClick={(e) => { e.stopPropagation(); onNavigate(files[currentIndex + 1]); }}
            className="absolute right-4 p-3 text-white bg-black/50 hover:bg-white/20 rounded-full transition-all border border-white/20 hover:border-white/40 shadow-lg z-10"
          >
            <ChevronRight className="h-8 w-8" />
          </button>
        )}

        {/* Media display */}
        {fileLoading || !fileUrl ? (
          <div className="flex flex-col items-center gap-4" onClick={(e) => e.stopPropagation()}>
            <Loader2 className="h-12 w-12 text-neon-cyan animate-spin" />
            <p className="text-gray-400 text-sm">Loading preview...</p>
          </div>
        ) : file.media_type === 'image' ? (
          <img
            src={fileUrl}
            alt={file.filename}
            className="max-w-full max-h-full object-contain rounded-lg shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          />
        ) : file.media_type === 'video' ? (
          <video
            controls
            autoPlay
            className="max-w-full max-h-full rounded-lg shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          >
            <source src={fileUrl} type={file.mime_type || 'video/mp4'} />
            Your browser does not support the video tag.
          </video>
        ) : file.media_type === 'audio' ? (
          <div className="flex flex-col items-center gap-6" onClick={(e) => e.stopPropagation()}>
            <Music className="h-24 w-24 text-neon-green opacity-40" />
            <audio controls autoPlay className="w-96">
              <source src={fileUrl} type={file.mime_type || 'audio/mpeg'} />
              Your browser does not support the audio element.
            </audio>
            <p className="text-gray-400 text-lg">{file.filename}</p>
          </div>
        ) : (
          <div className="flex flex-col items-center gap-4 text-gray-400" onClick={(e) => e.stopPropagation()}>
            <FileText className="h-24 w-24 opacity-40" />
            <p className="text-lg">{file.filename}</p>
            <p className="text-sm">No preview available for this file type</p>
          </div>
        )}
      </div>

      {/* Bottom counter */}
      <div className="text-center py-3 text-sm text-gray-400">
        {currentIndex + 1} / {files.length} · <span className="text-gray-500">click outside to close</span>
      </div>
    </div>
  );
};

// =============================================================================
// File Tile Component
// =============================================================================

interface FileTileProps {
  file: MediaFile;
  toolSlug: string;
  viewMode: 'grid' | 'list';
  isAdmin: boolean;
  onPreview: (file: MediaFile) => void;
  onDelete: (file: MediaFile) => void;
}

const FileTile: React.FC<FileTileProps> = ({
  file,
  toolSlug,
  viewMode,
  isAdmin,
  onPreview,
  onDelete,
}) => {
  const { icon: Icon, color } = getMediaTypeIcon(file.media_type);
  const canPreview = ['image', 'video', 'audio'].includes(file.media_type);

  const handleDownload = useCallback(async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      await mediaLibraryService.downloadFile(toolSlug, file.filename);
    } catch { /* silent */ }
  }, [toolSlug, file.filename]);

  const handleOpenNewTab = useCallback(async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      const blobUrl = await mediaLibraryService.fetchFileBlobUrl(toolSlug, file.filename);
      window.open(blobUrl, '_blank');
    } catch { /* silent */ }
  }, [toolSlug, file.filename]);

  if (viewMode === 'list') {
    return (
      <div className="group flex items-center gap-4 bg-gradient-to-r from-gray-900/90 to-gray-900/50 rounded-lg border border-gray-800 hover:border-neon-cyan/30 transition-all duration-200 p-3">
        {/* Icon / Thumbnail */}
        <div className="w-12 h-12 flex-shrink-0 rounded-lg overflow-hidden">
          {file.thumbnail_url ? (
            <ThumbnailImage toolSlug={toolSlug} file={file} className="w-12 h-12" />
          ) : (
            <div className="w-12 h-12 flex items-center justify-center bg-navy-900/60 rounded-lg">
              <Icon className={`h-6 w-6 ${color}`} />
            </div>
          )}
        </div>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium text-white truncate">{file.filename}</p>
          <p className="text-xs text-gray-500">
            {formatBytes(file.size_bytes)} · {formatTimeAgo(file.modified_at)}
          </p>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          {canPreview && (
            <button
              onClick={() => onPreview(file)}
              className="p-1.5 text-gray-400 hover:text-neon-cyan rounded-lg hover:bg-white/5"
              title="Preview"
            >
              <Eye className="h-4 w-4" />
            </button>
          )}
          <button
            onClick={handleOpenNewTab}
            className="p-1.5 text-gray-400 hover:text-white rounded-lg hover:bg-white/5"
            title="Open in new tab"
          >
            <ExternalLink className="h-4 w-4" />
          </button>
          <button
            onClick={handleDownload}
            className="p-1.5 text-gray-400 hover:text-neon-cyan rounded-lg hover:bg-white/5"
            title="Download"
          >
            <Download className="h-4 w-4" />
          </button>
          {isAdmin && (
            <button
              onClick={() => onDelete(file)}
              className="p-1.5 text-gray-400 hover:text-neon-pink rounded-lg hover:bg-white/5"
              title="Delete"
            >
              <Trash2 className="h-4 w-4" />
            </button>
          )}
        </div>
      </div>
    );
  }

  // Grid mode
  return (
    <div className="group relative bg-gradient-to-br from-gray-900/90 to-gray-900/50 rounded-xl border border-gray-800 hover:border-neon-cyan/40 transition-all duration-300 overflow-hidden hover:shadow-lg hover:shadow-neon-cyan/10">
      {/* Thumbnail area */}
      <div
        className="aspect-square cursor-pointer relative"
        onClick={() => canPreview && onPreview(file)}
      >
        <ThumbnailImage toolSlug={toolSlug} file={file} className="w-full h-full" />

        {/* Video play overlay */}
        {file.media_type === 'video' && (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-12 h-12 rounded-full bg-black/60 flex items-center justify-center backdrop-blur-sm group-hover:bg-neon-cyan/20 transition-colors">
              <Play className="h-5 w-5 text-white ml-0.5" />
            </div>
          </div>
        )}

        {/* Hover overlay with actions */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-200">
          <div className="absolute bottom-2 right-2 flex gap-1">
            {canPreview && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onPreview(file);
                }}
                className="p-1.5 bg-black/60 hover:bg-neon-cyan/30 text-white rounded-lg backdrop-blur-sm transition-colors"
                title="Preview"
              >
                <Eye className="h-4 w-4" />
              </button>
            )}
            <button
              onClick={handleOpenNewTab}
              className="p-1.5 bg-black/60 hover:bg-white/20 text-white rounded-lg backdrop-blur-sm transition-colors"
              title="Open in new tab"
            >
              <ExternalLink className="h-4 w-4" />
            </button>
            <button
              onClick={handleDownload}
              className="p-1.5 bg-black/60 hover:bg-neon-cyan/30 text-white rounded-lg backdrop-blur-sm transition-colors"
              title="Download"
            >
              <Download className="h-4 w-4" />
            </button>
            {isAdmin && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onDelete(file);
                }}
                className="p-1.5 bg-black/60 hover:bg-neon-pink/30 text-white rounded-lg backdrop-blur-sm transition-colors"
                title="Delete"
              >
                <Trash2 className="h-4 w-4" />
              </button>
            )}
          </div>
        </div>
      </div>

      {/* File info footer */}
      <div className="p-3 border-t border-gray-800">
        <p className="text-sm text-white truncate font-medium" title={file.filename}>
          {file.filename}
        </p>
        <div className="flex items-center justify-between mt-1">
          <span className="text-xs text-gray-500">{formatBytes(file.size_bytes)}</span>
          <span className="text-xs text-gray-500">{formatTimeAgo(file.modified_at)}</span>
        </div>
      </div>
    </div>
  );
};

