// =============================================================================
// Stats Bar Component
// =============================================================================

interface StatsBarProps {
  stats: MediaStats | undefined;
  isLoading: boolean;
}

const StatsBar: React.FC<StatsBarProps> = ({ stats, isLoading }) => {
  if (isLoading || !stats) return null;

  return (
    <div className="flex flex-wrap items-center gap-4 px-5 py-3 bg-navy-800/50 rounded-xl border border-gray-800">
      <div className="flex items-center gap-2">
        <HardDrive className="h-4 w-4 text-neon-cyan" />
        <span className="text-sm text-white font-medium">{stats.total_files} files</span>
        <span className="text-xs text-gray-500">({formatBytes(stats.total_size_bytes)})</span>
      </div>
      <div className="h-4 w-px bg-gray-700" />
      {(Object.entries(stats.by_type) as [string, number][])
        .sort(([, a], [, b]) => b - a)
        .map(([type, count]) => {
          const { icon: Icon, color } = getMediaTypeIcon(type);
          return (
            <span
              key={type}
              className="inline-flex items-center gap-1.5 text-xs text-gray-400"
            >
              <Icon className={`h-3.5 w-3.5 ${color}`} />
              {count} {type}
            </span>
          );
        })}
    </div>
  );
};

// =============================================================================
// Main MediaLibraryTab Component
// =============================================================================

type SortBy = 'modified_at' | 'name' | 'size';
type SortOrder = 'asc' | 'desc';

export const MediaLibraryTab: React.FC = () => {
  const { user } = useAuthStore();
  const queryClient = useQueryClient();
  const isAdmin = user?.role === 'admin';

  // State
  const [selectedTool, setSelectedTool] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [sortBy, setSortBy] = useState<SortBy>('modified_at');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [mediaTypeFilter, setMediaTypeFilter] = useState<string | undefined>(undefined);
  const [lightboxFile, setLightboxFile] = useState<MediaFile | null>(null);
  const [page, setPage] = useState(1);
  const thumbnailsTriggered = useRef<Set<string>>(new Set());

  // Reset page when filters change
  useEffect(() => {
    setPage(1);
  }, [sortBy, sortOrder, mediaTypeFilter, selectedTool]);

  // Queries
  const { data: tools, isLoading: toolsLoading } = useQuery({
    queryKey: ['media-library', 'tools'],
    queryFn: () => mediaLibraryService.listToolsWithMedia(),
    refetchInterval: 30000,
  });

  const { data: stats, isLoading: statsLoading } = useQuery({
    queryKey: ['media-library', 'stats'],
    queryFn: () => mediaLibraryService.getStats(),
  });

  const { data: fileList, isLoading: filesLoading } = useQuery({
    queryKey: ['media-library', 'files', selectedTool, page, sortBy, sortOrder, mediaTypeFilter],
    queryFn: () =>
      mediaLibraryService.listFiles(selectedTool!, {
        page,
        page_size: 50,
        sort_by: sortBy,
        sort_order: sortOrder,
        media_type: mediaTypeFilter,
      }),
    enabled: !!selectedTool,
    refetchInterval: 15000, // Refresh to pick up thumbnail changes
  });

  // Auto-trigger thumbnail generation for the selected tool
  useEffect(() => {
    if (selectedTool && fileList && !thumbnailsTriggered.current.has(selectedTool)) {
      const needsThumbnails = fileList.files.some(
        (f) => !f.has_thumbnail && ['image', 'video', 'audio'].includes(f.media_type)
      );
      if (needsThumbnails) {
        thumbnailsTriggered.current.add(selectedTool);
        mediaLibraryService.generateThumbnails(selectedTool).catch(() => {
          // Non-critical — thumbnails will be generated on-demand
        });
      }
    }
  }, [selectedTool, fileList]);

  // Find selected tool metadata
  const selectedToolMeta = tools?.find((t) => t.slug === selectedTool);

  // Handlers
  const handleDeleteFile = async (file: MediaFile) => {
    if (!selectedTool) return;
    if (!window.confirm(`Delete ${file.filename}? This cannot be undone.`)) return;
    try {
      await mediaLibraryService.deleteFile(selectedTool, file.filename);
      queryClient.invalidateQueries({ queryKey: ['media-library'] });
    } catch {
      // Error handled by API client interceptor
    }
  };

  const handleToolClick = (slug: string) => {
    setSelectedTool(slug);
    setPage(1);
    setMediaTypeFilter(undefined);
  };

  const handleBack = () => {
    setSelectedTool(null);
    setMediaTypeFilter(undefined);
    setPage(1);
  };

  // Get all previewable files for lightbox navigation
  const previewableFiles =
    fileList?.files.filter((f) => ['image', 'video', 'audio'].includes(f.media_type)) || [];

  // =====================================================================
  // Render: Loading State
  // =====================================================================

  if (toolsLoading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 className="h-8 w-8 animate-spin text-neon-cyan" />
      </div>
    );
  }

  // =====================================================================
  // Render: Tool Files View
  // =====================================================================

  if (selectedTool && selectedToolMeta) {
    return (
      <div className="space-y-5">
        {/* Breadcrumb / Back navigation */}
        <div className="flex items-center gap-3">
          <button
            onClick={handleBack}
            className="inline-flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-neon-cyan bg-neon-cyan/10 hover:bg-neon-cyan/20 border border-neon-cyan/30 hover:border-neon-cyan/50 rounded-lg transition-colors"
          >
            <ChevronLeft className="h-5 w-5" />
            Media Library
          </button>
          <span className="text-gray-600 text-lg">/</span>
          <span className="text-white font-semibold text-base">{selectedToolMeta.display_name}</span>
          <span className="text-gray-400 text-sm">
            ({fileList?.total_count ?? 0} files · {formatBytes(fileList?.total_size_bytes ?? 0)})
          </span>
        </div>

        {/* Controls */}
        <div className="flex flex-wrap items-center gap-3">
          {/* Media type filter chips */}
          <div className="flex items-center gap-2 flex-wrap">
            <button
              onClick={() => setMediaTypeFilter(undefined)}
              className={`px-3 py-1.5 text-xs font-medium rounded-full border transition-colors ${
                !mediaTypeFilter
                  ? 'bg-neon-cyan/10 text-neon-cyan border-neon-cyan/30'
                  : 'bg-gray-800/50 text-gray-400 border-gray-700 hover:text-white hover:border-gray-500'
              }`}
            >
              All
            </button>
            {['image', 'video', 'audio', 'document'].map((type) => {
              const { icon: Icon, color } = getMediaTypeIcon(type);
              return (
                <button
                  key={type}
                  onClick={() => setMediaTypeFilter(type === mediaTypeFilter ? undefined : type)}
                  className={`px-3 py-1.5 text-xs font-medium rounded-full border transition-colors flex items-center gap-1.5 ${
                    mediaTypeFilter === type
                      ? 'bg-neon-cyan/10 text-neon-cyan border-neon-cyan/30'
                      : 'bg-gray-800/50 text-gray-400 border-gray-700 hover:text-white hover:border-gray-500'
                  }`}
                >
                  <Icon className={`h-3 w-3 ${mediaTypeFilter === type ? 'text-neon-cyan' : color}`} />
                  {type.charAt(0).toUpperCase() + type.slice(1)}
                </button>
              );
            })}
          </div>

          <div className="flex-1" />

          {/* Sort */}
          <div className="flex items-center gap-2">
            <ArrowUpDown className="h-4 w-4 text-gray-500" />
            <select
              value={`${sortBy}-${sortOrder}`}
              onChange={(e) => {
                const [by, order] = e.target.value.split('-') as [SortBy, SortOrder];
                setSortBy(by);
                setSortOrder(order);
              }}
              className="px-3 py-1.5 text-xs bg-gray-900/50 border border-gray-700 rounded-lg text-white focus:border-neon-cyan"
            >
              <option value="modified_at-desc">Newest First</option>
              <option value="modified_at-asc">Oldest First</option>
              <option value="name-asc">Name A-Z</option>
              <option value="name-desc">Name Z-A</option>
              <option value="size-desc">Largest First</option>
              <option value="size-asc">Smallest First</option>
            </select>
          </div>

          {/* View toggle */}
          <div className="flex items-center gap-1">
            <button
              onClick={() => setViewMode('grid')}
              className={`p-1.5 rounded-lg transition-colors ${
                viewMode === 'grid'
                  ? 'bg-neon-cyan/20 text-neon-cyan'
                  : 'bg-gray-900/50 text-gray-400 hover:text-white'
              }`}
            >
              <Grid className="h-4 w-4" />
            </button>
            <button
              onClick={() => setViewMode('list')}
              className={`p-1.5 rounded-lg transition-colors ${
                viewMode === 'list'
                  ? 'bg-neon-cyan/20 text-neon-cyan'
                  : 'bg-gray-900/50 text-gray-400 hover:text-white'
              }`}
            >
              <List className="h-4 w-4" />
            </button>
          </div>
        </div>

        {/* File grid/list */}
        {filesLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-neon-cyan" />
          </div>
        ) : !fileList || fileList.files.length === 0 ? (
          <div className="text-center py-16">
            <FolderOpen className="h-16 w-16 mx-auto mb-4 text-gray-600" />
            <h3 className="text-lg font-semibold text-gray-400 mb-2">No files yet</h3>
            <p className="text-gray-500 text-sm">
              Run this tool from the Workbench to generate media
            </p>
          </div>
        ) : viewMode === 'grid' ? (
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
            {fileList.files.map((file) => (
              <FileTile
                key={file.filename}
                file={file}
                toolSlug={selectedTool}
                viewMode="grid"
                isAdmin={isAdmin}
                onPreview={(f) => setLightboxFile(f)}
                onDelete={handleDeleteFile}
              />
            ))}
          </div>
        ) : (
          <div className="space-y-2">
            {fileList.files.map((file) => (
              <FileTile
                key={file.filename}
                file={file}
                toolSlug={selectedTool}
                viewMode="list"
                isAdmin={isAdmin}
                onPreview={(f) => setLightboxFile(f)}
                onDelete={handleDeleteFile}
              />
            ))}
          </div>
        )}

        {/* Pagination */}
        {fileList && fileList.total_count > fileList.page_size && (
          <div className="flex items-center justify-center gap-4 pt-4">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page <= 1}
              className="px-4 py-2 text-sm bg-gray-900/50 border border-gray-700 rounded-lg text-gray-400 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed"
            >
              Previous
            </button>
            <span className="text-sm text-gray-500">
              Page {page} of {Math.ceil(fileList.total_count / fileList.page_size)}
            </span>
            <button
              onClick={() => setPage((p) => p + 1)}
              disabled={!fileList.has_more}
              className="px-4 py-2 text-sm bg-gray-900/50 border border-gray-700 rounded-lg text-gray-400 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed"
            >
              Next
            </button>
          </div>
        )}

        {/* Lightbox */}
        {lightboxFile && selectedTool && (
          <Lightbox
            file={lightboxFile}
            toolSlug={selectedTool}
            files={previewableFiles}
            onClose={() => setLightboxFile(null)}
            onNavigate={(f) => setLightboxFile(f)}
          />
        )}
      </div>
    );
  }

  // =====================================================================
  // Render: Overview (Tool Cards)
  // =====================================================================

  const toolsWithFiles = tools?.filter((t) => t.file_count > 0) || [];
  const toolsEmpty = tools?.filter((t) => t.file_count === 0) || [];

  return (
    <div className="space-y-6">
      {/* Global stats */}
      <StatsBar stats={stats} isLoading={statsLoading} />

      {/* Tools with files */}
      {toolsWithFiles.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {toolsWithFiles.map((tool) => (
            <ToolCard key={tool.slug} tool={tool} onClick={() => handleToolClick(tool.slug)} />
          ))}
        </div>
      ) : (
        <div className="text-center py-16">
          <FolderOpen className="h-20 w-20 mx-auto mb-4 text-gray-600" />
          <h3 className="text-xl font-semibold text-gray-400 mb-2">No generated media yet</h3>
          <p className="text-gray-500">
            Run tools from the Workbench to start generating images, videos, audio, and more
          </p>
        </div>
      )}

      {/* Collapsed section for tools with no files */}
      {toolsEmpty.length > 0 && toolsWithFiles.length > 0 && (
        <EmptyToolsSection tools={toolsEmpty} />
      )}
    </div>
  );
};

// =============================================================================
// Collapsible empty tools section
// =============================================================================

const EmptyToolsSection: React.FC<{ tools: ToolMediaSummary[] }> = ({ tools }) => {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className="border-t border-gray-800 pt-4">
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex items-center gap-2 text-sm text-gray-500 hover:text-gray-300 transition-colors"
      >
        <ChevronDown
          className={`h-4 w-4 transition-transform ${expanded ? 'rotate-180' : ''}`}
        />
        {tools.length} tool{tools.length !== 1 ? 's' : ''} with no output files
      </button>
      {expanded && (
        <div className="mt-3 grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
          {tools.map((tool) => (
            <div
              key={tool.slug}
              className="flex items-center gap-2 px-3 py-2 bg-gray-900/30 rounded-lg border border-gray-800/50 text-gray-500 text-sm"
            >
              <span>{TOOL_ICON_MAP[tool.icon] || '📁'}</span>
              <span className="truncate">{tool.display_name}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MediaLibraryTab;
